import { createArmorViewModel, createHelmetViewModel } from './armor.functions.js';
import { createAttributesViewModel } from './attributes.functions.js';
import { createShieldViewModel } from './shield.functions.js';
import { createAllSkillsValuesViewModel } from './skills.functions.js';
import { createWeaponViewModel } from './weapon.functions.js';
export const createTypicalKinViewModel = tk => {
  return { ...tk,
    collapse: true,
    attributes: createAttributesViewModel(tk.attributes),
    skills: createAllSkillsValuesViewModel(tk.skills),
    weapons: tk.weapons.map(createWeaponViewModel),
    shields: tk.shields.map(createShieldViewModel),
    armors: tk.armors.map(createArmorViewModel),
    helmets: tk.helmets.map(createHelmetViewModel)
  };
};